// GenerateToken creates an HMAC-signed token for a service
func (tv *TokenValidator) GenerateToken(serviceName string) (string, error) {
	svc, exists := tv.knownServices[serviceName]
	if !exists || !svc.Active {
		return "", fmt.Errorf("unknown or inactive service: %s", serviceName)
	}

	timestamp := time.Now().UTC().Format(time.RFC3339)
	payload := fmt.Sprintf("%s|%s|%s", serviceName, svc.Namespace, timestamp)

	mac := hmac.New(sha256.New, tv.secret)
	mac.Write([]byte(payload))
	signature := hex.EncodeToString(mac.Sum(nil))

	token := fmt.Sprintf("%s.%s", payload, signature)
	return token, nil
}

// ValidateToken validates an HMAC-signed token and returns the service identity
func (tv *TokenValidator) ValidateToken(token string) (*ServiceIdentity, error) {
	if token == "" {
		return nil, fmt.Errorf("empty token")
	}

	// Check if token is revoked
	if _, revoked := tv.revokedTokens[token]; revoked {
		return nil, fmt.Errorf("token has been revoked")
	}

	// Split token into payload and signature
	lastDot := strings.LastIndex(token, ".")
	if lastDot == -1 {
		return nil, fmt.Errorf("malformed token: missing signature")
	}

	payload := token[:lastDot]
	providedSig := token[lastDot+1:]

	// Verify HMAC signature
	mac := hmac.New(sha256.New, tv.secret)
	mac.Write([]byte(payload))
	expectedSig := hex.EncodeToString(mac.Sum(nil))

	if !hmac.Equal([]byte(providedSig), []byte(expectedSig)) {
		return nil, fmt.Errorf("invalid token signature")
	}

	// Parse payload
	parts := strings.Split(payload, "|")
	if len(parts) != 3 {
		return nil, fmt.Errorf("malformed token payload")
	}

	serviceName := parts[0]
	namespace := parts[1]
	timestampStr := parts[2]

	// Verify timestamp (token expiration)
	tokenTime, err := time.Parse(time.RFC3339, timestampStr)
	if err != nil {
		return nil, fmt.Errorf("invalid token timestamp: %v", err)
	}

	if time.Since(tokenTime) > tokenExpiration {
		return nil, fmt.Errorf("token expired")
	}

	// Verify service is known and active
	svc, exists := tv.knownServices[serviceName]
	if !exists {
		return nil, fmt.Errorf("unknown service: %s", serviceName)
	}
	if !svc.Active {
		return nil, fmt.Errorf("service is inactive: %s", serviceName)
	}
	if svc.Namespace != namespace {
		return nil, fmt.Errorf("namespace mismatch for service: %s", serviceName)
	}

	return &ServiceIdentity{
		ServiceName: serviceName,
		Namespace:   namespace,
		Permissions: svc.Permissions,
		AuthTime:    tokenTime,
	}, nil
}

// RevokeToken adds a token to the revocation list
func (tv *TokenValidator) RevokeToken(token string) {
	tv.revokedTokens[token] = time.Now()
}

// HasPermission checks if a service identity has a specific permission
func (si *ServiceIdentity) HasPermission(permission string) bool {
	for _, p := range si.Permissions {
		if p == permission {
			return true
		}
	}
	return false
}

