// UnaryInterceptor handles authentication for unary RPCs
func (ai *AuthInterceptor) UnaryInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Skip auth for public methods
		if ai.publicMethods[info.FullMethod] {
			log.Printf("[AUTH] Skipping auth for public method: %s", info.FullMethod)
			return handler(ctx, req)
		}

		// Extract and validate token from metadata
		identity, err := ai.authenticate(ctx)
		if err != nil {
			log.Printf("[AUTH] Authentication failed for method %s: %v", info.FullMethod, err)
			return nil, err
		}

		log.Printf("[AUTH] Authenticated service=%s namespace=%s method=%s",
			identity.ServiceName, identity.Namespace, info.FullMethod)

		// Add identity to context
		newCtx := ContextWithIdentity(ctx, identity)

		// Call the handler
		resp, err := handler(newCtx, req)
		return resp, err
	}
}

// StreamInterceptor handles authentication for streaming RPCs
func (ai *AuthInterceptor) StreamInterceptor() grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		if ai.publicMethods[info.FullMethod] {
			return handler(srv, ss)
		}

		identity, err := ai.authenticate(ss.Context())
		if err != nil {
			log.Printf("[AUTH] Stream authentication failed for method %s: %v", info.FullMethod, err)
			return err
		}

		log.Printf("[AUTH] Stream authenticated service=%s method=%s",
			identity.ServiceName, info.FullMethod)

		// Wrap the stream with authenticated context
		wrappedStream := &authenticatedStream{
			ServerStream: ss,
			ctx:          ContextWithIdentity(ss.Context(), identity),
		}

		return handler(srv, wrappedStream)
	}
}

// authenticate extracts and validates the auth token from gRPC metadata
func (ai *AuthInterceptor) authenticate(ctx context.Context) (*ServiceIdentity, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "missing metadata")
	}

	// Extract auth token
	tokens := md.Get(tokenHeader)
	if len(tokens) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing authentication token")
	}
	token := tokens[0]

	// Extract optional service name for additional validation
	serviceNames := md.Get(serviceHeader)
	var declaredService string
	if len(serviceNames) > 0 {
		declaredService = serviceNames[0]
	}

	// Extract request ID for tracing
	requestIDs := md.Get(requestIDHeader)
	if len(requestIDs) > 0 {
		log.Printf("[AUTH] Processing request ID: %s", requestIDs[0])
	}

	// Validate token
	identity, err := ai.validator.ValidateToken(token)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
	}

	// Cross-check declared service name if provided
	if declaredService != "" && declaredService != identity.ServiceName {
		return nil, status.Errorf(codes.Unauthenticated,
			"service name mismatch: declared=%s, token=%s", declaredService, identity.ServiceName)
	}

	return identity, nil
}

